// ──────────────────────────────────────────
// XP levels
// ──────────────────────────────────────────
export const LEVELS = [
  [0,    100,  'Apprentice'],
  [100,  280,  'Planner'],
  [280,  560,  'Architect'],
  [560,  1000, 'Mayor'],
]

export function getLevel(xp) {
  for (const [a, b, l] of LEVELS) {
    if (xp >= a && xp < b) return { min: a, max: b, label: l }
  }
  return { min: 560, max: 1000, label: 'Mayor' }
}

