// ──────────────────────────────────────────
// Selectors / helpers
// ──────────────────────────────────────────
export function toolsForGate(g) {
  return TOOLS.filter(t => t.g.includes(g))
}

export function toolsForGateDim(g, dim) {
  return TOOLS.filter(t => t.g.includes(g) && t.d?.includes(dim))
}

// Skill levels carried by `practiced[toolName]`. Weights drive the radar
// polygon depth — a dim filled with regular practitioners scores 1×,
// occasional 0.6×, theoretical knowledge 0.3×.
export const SKILL_LEVELS = {
  regular:    { weight: 1.0,  label: 'Regular practice',     short: 'Regular'    },
  occasional: { weight: 0.6,  label: 'Occasional practice',  short: 'Occasional' },
  theory:     { weight: 0.3,  label: 'Theoretical knowledge', short: 'Theory'    },
}
const LEVEL_W = Object.fromEntries(
  Object.entries(SKILL_LEVELS).map(([k, v]) => [k, v.weight])
)

// Read helper: works with either the new object shape ({name: level})
// OR the legacy Set<name> still used in a few hot paths.
const has = (practiced, name) =>
  practiced && (typeof practiced.has === 'function' ? practiced.has(name) : !!practiced[name])

const levelOf = (practiced, name) =>
  practiced && typeof practiced.has === 'function' ? (practiced.has(name) ? 'regular' : null) : (practiced?.[name] ?? null)

// Count of tools the user has logged any opinion on (regular/occasional/theory).
export function practicedForGate(g, practiced) {
  return toolsForGate(g).filter(t => has(practiced, t.n)).length
}
export function practicedForGateDim(g, dim, practiced) {
  return toolsForGateDim(g, dim).filter(t => has(practiced, t.n)).length
}

// Weighted score (0..1 per dim/gate) — drives the radar polygon vertices
// so the gate visually reflects DEPTH of capability, not just headcount.
export function scoreForGateDim(g, dim, practiced) {
  return toolsForGateDim(g, dim).reduce(
    (s, t) => s + (LEVEL_W[levelOf(practiced, t.n)] || 0), 0
  )
}
export function scoreForGate(g, practiced) {
  return toolsForGate(g).reduce(
    (s, t) => s + (LEVEL_W[levelOf(practiced, t.n)] || 0), 0
  )
}

export function isUnlocked(g, practiced) {
  if (g === 1) return true
  const prev = toolsForGate(g - 1)
  const need = Math.max(3, Math.ceil(prev.length * 0.3))
  return practicedForGate(g - 1, practiced) >= need
}

export function unlockThreshold(g) {
  if (g === 1) return 0
  const prev = toolsForGate(g - 1)
  return Math.max(3, Math.ceil(prev.length * 0.3))
}
